  ('promotion-6ec17a12-moex-00077', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-110-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'essay', '某直轄市政府為提升轄區內公共場所升降機之安全性，制定自治條例明
定升降機應定期安全檢查，檢查合格者除給予書面證書外，另貼上合格
標章，公示檢查日期與效期，以發揮大眾一起監督之效果。惟市政府人
力有限，擬開放民間業者執行安全檢查工作，檢查合格者由業者製發書
面證書交其收執，另為提升合格標章之公信力，規定必須貼用市政府製
作之標章。試問：民間檢查業者代替市政府執行安全檢查工作之法律性
質為何？設置某公共場所升降機之私人業者不服檢查未通過之文書，應
向何者提起行政救濟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:43+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "131", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL)
